function reveal(){const o=new IntersectionObserver(es=>es.forEach(x=>x.target.classList.toggle('visible',x.isIntersecting)),{threshold:.08,rootMargin:'0px 0px -8% 0px'});$$('.reveal').forEach(x=>o.observe(x))}
function injectCommerceAssets(){if(!document.querySelector('link[data-commerce-css]')){const link=document.createElement('link');link.rel='stylesheet';link.href='/commerce.css?v=20260717-1';link.dataset.commerceCss='true';document.head.appendChild(link)}const details=[...$$('.faq-list details')].find(item=>item.querySelector('summary')?.textContent.includes('¿Qué precio tienen?'));if(details){const paragraph=details.querySelector('p');if(paragraph)paragraph.innerHTML='Las bebidas empiezan en $65 c/u y manejamos precios especiales por volumen.<br><br><b>Estándar:</b><br>1–5: $65<br>6–10: $60<br>11–20: $58<br>21–49: $55<br>50–99: $53<br>100–149: $52<br>150+: $50<br><br><b>Personalizadas desde 50 piezas:</b><br>50–99: $65<br>100–149: $62<br>150+: $60<br><br>El envío se calcula por separado.'}}
