function init(){injectCommerceAssets();if(!sessionStorage.getItem('antojo_session'))sessionStorage.setItem('antojo_session',`s_${Date.now()}_${Math.random().toString(36).slice(2,8)}`);fillImages();renderFavorites();renderMenu();$('#cartBadge').textContent=total();bind();reveal();startCarousel();route(state.screen==='success'&&state.success?'success':state.screen||'home');hideLoader()}
